3	export function nextGeneration(cells: Cell[]): Cell[] {
4	  const liveSet = new Set<string>();
5	  for (const [x, y] of cells) {
6	    liveSet.add(key(x, y));
7	  }
8	
9	  const neighborCounts = new Map<string, number>();
10	
11	  for (const [x, y] of cells) {
12	    for (let dx = -1; dx <= 1; dx++) {
13	      for (let dy = -1; dy <= 1; dy++) {
14	        if (dx === 0 && dy === 0) continue;
15	        const nx = x + dx;
16	        const ny = y + dy;
17	        const k = key(nx, ny);
18	        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
19	      }
20	    }
21	  }
22	
23	  const result: Cell[] = [];
24	
25	  for (const [k, count] of neighborCounts) {
26	    const isAlive = liveSet.has(k);
27	    if (isAlive && (count === 2 || count === 3)) {
28	      result.push(parseKey(k));
29	    } else if (!isAlive && count === 3) {
30	      result.push(parseKey(k));
31	    }
32	  }
33	
34	  return result;
35	}
36	
37	function key(x: number, y: number): string {
38	  return `${x},${y}`;
39	}
40	
41	function parseKey(k: string): Cell {
42	  const [xStr, yStr] = k.split(",");
43	  return [Number(xStr), Number(yStr)];
44	}
